toJulianDay(date: AnyCalendarDate): number {
  let extendedYear = date.year + INDIAN_ERA_START;
  let [era, year] = fromExtendedYear(extendedYear);

  let leapMonth: number;
  let jd: number;
  if (isLeapYear(year)) {
    leapMonth = 31;
    jd = gregorianToJulianDay(era, year, 3, 21);
  } else {
    leapMonth = 30;
    jd = gregorianToJulianDay(era, year, 3, 22);
  }

  if (date.month === 1) {
    return jd + date.day - 1;
  }

  jd += leapMonth + Math.min(date.month - 2, 5) * 31;

  if (date.month >= 8) {
    jd += (date.month - 7) * 30;
  }

  jd += date.day - 1;
  return jd;
}

export function parseDateTime(value: string): CalendarDateTime {
  let m = value.match(DATE_TIME_RE);
  if (!m) {
    if (ABSOLUTE_RE.test(value)) {
      throw new Error(`Invalid ISO 8601 date time string: ${value}. Use parseAbsolute() instead.`);
    }
    throw new Error('Invalid ISO 8601 date time string: ' + value);
  }

  let year = parseNumber(m[1], -9999, 9999);
  let era = year < 1 ? 'BC' : 'AD';

  let date: Mutable<CalendarDateTime> = new CalendarDateTime(
    era,
    year < 1 ? -year + 1 : year,
    parseNumber(m[2], 1, 12),
    1,
    m[4] ? parseNumber(m[4], 0, 23) : 0,
    m[5] ? parseNumber(m[5], 0, 59) : 0,
    m[6] ? parseNumber(m[6], 0, 59) : 0,
    m[7] ? parseNumber(m[7], 0, Infinity) * 1000 : 0
  );

  date.day = parseNumber(m[3], 0, date.calendar.getDaysInMonth(date));
  return date as CalendarDateTime;
}

function antdCodeAppend(docFileAbs: string, src: string): string {
  const docDir = path.dirname(docFileAbs);
  const locale = detectDocLocale(docFileAbs);
  const demoAbs = path.resolve(docDir, src);
  const demoMdAbs = demoAbs.replace(path.extname(src), '.md');
  const demoMd = fs.existsSync(demoMdAbs) ? fs.readFileSync(demoMdAbs, 'utf-8') : '';
  const other = locale === 'zh-CN' ? 'en-US' : 'zh-CN';
  const re = new RegExp(
    `(^|\\n)##\\s*${locale}\\s*\\n([\\s\\S]*?)(?=\\n##\\s*${other}\\s*\\n|$)`,
    'i',
  );
  const match = demoMd.match(re);
  if (!match) {
    return demoMd.trim();
  }
  return (match[2] ?? '').trim();
}

const useChildDom = (
  children: React.ReactNode,
): [childNode: React.ReactNode, domNode: HTMLElement | SVGElement | null] => {
  const [domNode, setDomNode] = React.useState<HTMLElement | SVGElement | null>(null);
  const childNode = React.isValidElement(children) ? children : null;
  const internalRef = React.useCallback(
    (node: React.ReactInstance | HTMLElement | SVGElement | null) => {
      const nextDom = getDOM(node);

      setDomNode((prevDom) => (prevDom === nextDom ? prevDom : nextDom));
    },
    [],
  );
  const mergedRef = useComposeRef(childNode ? getNodeRef(childNode) : null, internalRef);

  if (!childNode || !supportRef(childNode)) {
    return [children, domNode];
  }

  return [cloneElement(childNode, { ref: mergedRef }), domNode];
};

function collectNextLinkImports(j: any, root: any): Set<string> {
  const nextLinkNames = new Set<string>()

  root
    .find(j.ImportDeclaration, { source: { value: "next/link" } })
    .forEach((path: any) => {
      path.node.specifiers?.forEach((spec: any) => {
        if (
          spec.type === "ImportDefaultSpecifier" &&
          spec.local?.type === "Identifier"
        ) {
          nextLinkNames.add(spec.local.name)
        }
        if (
          spec.type === "ImportSpecifier" &&
          spec.local?.type === "Identifier"
        ) {
          nextLinkNames.add(spec.local.name)
        }
      })
    })

  return nextLinkNames
}

export function getPackageManager(): PackageManager {
  if (fs.existsSync(path.join(process.cwd(), "pnpm-lock.yaml"))) {
    return "pnpm"
  }

  if (fs.existsSync(path.join(process.cwd(), "yarn.lock"))) {
    return "yarn"
  }

  if (fs.existsSync(path.join(process.cwd(), "bun.lockb"))) {
    return "bun"
  }

  if (fs.existsSync(path.join(process.cwd(), "package-lock.json"))) {
    return "npm"
  }

  const userAgent = process.env.npm_config_user_agent

  if (userAgent) {
    if (userAgent.startsWith("pnpm")) return "pnpm"
    if (userAgent.startsWith("yarn")) return "yarn"
    if (userAgent.startsWith("bun")) return "bun"
  }

  // Default to npm
  return "npm"
}

export async function execWithOutput(
  command: string,
  args: string[],
  options: { ignoreReturnCode?: boolean; cwd: string }
) {
  process.stdout.write(`Running: ${command} ${args.join(" ")}` + os.EOL);
  let childProcess = spawn(command, args, {
    cwd: options.cwd,
  });
  childProcess.on("stdout", (data) => process.stdout.write(data));
  childProcess.on("stderr", (data) => process.stderr.write(data));
  let result = await childProcess;
  if (!options?.ignoreReturnCode && result.code !== 0) {
    throw new Error(
      `The command "${command} ${args.join(" ")}" failed with code ${
        result.code
      }\n${result.stdout.toString("utf8")}\n${result.stderr.toString("utf8")}`
    );
  }
  return {
    code: result.code,
    stdout: result.stdout.toString("utf8"),
    stderr: result.stderr.toString("utf8"),
  };
}

export function formatNumber(val: number): string {
  if (val >= 1e12) {
    return `${toFixed(val / 1e12)}T`;
  }
  if (val >= 1e9) {
    return `${toFixed(val / 1e9)}B`;
  }
  if (val >= 1e6) {
    return `${toFixed(val / 1e6)}M`;
  }
  if (val >= 1e3) {
    return `${toFixed(val / 1e3)}k`;
  }
  if (val >= 1) {
    return val.toString();
  }
  if (val >= 1e-3) {
    return `${toFixed(val * 1e3)}m`;
  }
  if (val >= 1e-6) {
    return `${toFixed(val * 1e6)}µ`;
  }
  if (val >= 1e-9) {
    return `${toFixed(val * 1e9)}n`;
  }
  if (val >= 1e-12) {
    return `${toFixed(val * 1e12)}p`;
  }
  return val.toString();
}

export function initializeContext(params: JSONSchemaGeneratorParams): ToJSONSchemaContext {
  // Normalize target: convert old non-hyphenated versions to hyphenated versions
  let target: ToJSONSchemaContext["target"] = params?.target ?? "draft-2020-12";
  if (target === "draft-4") target = "draft-04";
  if (target === "draft-7") target = "draft-07";

  return {
    processors: params.processors ?? {},
    metadataRegistry: params?.metadata ?? globalRegistry,
    target,
    unrepresentable: params?.unrepresentable ?? "throw",
    override: (params?.override as any) ?? (() => {}),
    io: params?.io ?? "output",
    counter: 0,
    seen: new Map(),
    cycles: params?.cycles ?? "ref",
    reused: params?.reused ?? "inline",
    external: params?.external ?? undefined,
  };
}

static object(obj: { [key: string]: WriterFunctionOrValue | undefined }): WriterFunction {
  return (writer: CodeBlockWriter) => {
    const keyNames = Object.keys(obj);
    writer.write("{");
    if (keyNames.length > 0) {
      writer.indent(() => {
        writeObject();
      });
    }
    writer.write("}");

    function writeObject() {
      for (let i = 0; i < keyNames.length; i++) {
        if (i > 0)
          writer.write(",").newLine();

        const keyName = keyNames[i];
        const value = obj[keyName];
        writer.write(keyName);
        if (value != null) {
          writer.write(": ");
          writeValue(writer, value);
        }
      }

      writer.newLine();
    }
  };
}

export function getDigitParts({
  value,
  decimalScale,
  fixedDecimalScale,
}: GetDigitPartsInput): DigitParts {
  const abs = Math.abs(value);
  let str = toPlainString(abs, decimalScale);

  if (!fixedDecimalScale && decimalScale !== undefined) {
    const parts = str.split('.');
    if (parts[1]) {
      const trimmed = parts[1].replace(/0+$/, '');
      str = trimmed ? `${parts[0]}.${trimmed}` : parts[0];
    }
  }

  const dotIdx = str.indexOf('.');
  const intStr = dotIdx >= 0 ? str.slice(0, dotIdx) : str;
  const fracStr = dotIdx >= 0 ? str.slice(dotIdx + 1) : '';

  return {
    negative: value < 0,
    intDigits: intStr.split(''),
    fracDigits: fracStr ? fracStr.split('') : [],
    hasDecimal: dotIdx >= 0,
  };
}

const getPolarAxisTickProps = (data: Data[], ax: IPolarAxisObject): PolarAxisProps => {
  const props: PolarAxisProps = {};

  if ((!ax.tickmode || ax.tickmode === 'array') && isArrayOrTypedArray(ax.tickvals)) {
    const tickValues = ax._type === 'date' ? ax.tickvals!.map((v: string | number | Date) => new Date(v)) : ax.tickvals;

    props.tickValues = tickValues;
    props.tickText = ax.ticktext;
    return props;
  }

  if ((!ax.tickmode || ax.tickmode === 'linear') && ax.dtick) {
    const dtick = plotlyDtick(ax.dtick, ax._type);
    const tick0 = plotlyTick0(ax.tick0, ax._type, dtick);

    props.tickStep = dtick;
    props.tick0 = tick0;
    return props;
  }

  if ((!ax.tickmode || ax.tickmode === 'auto') && typeof ax.nticks === 'number' && ax.nticks >= 0) {
    props.tickCount = ax.nticks;
  }

  return props;
};

function interpolateHexColor(c1: string, c2: string, t: number): string {
  const r1 = parseInt(c1.slice(1, 3), 16);
  const g1 = parseInt(c1.slice(3, 5), 16);
  const b1 = parseInt(c1.slice(5, 7), 16);
  const r2 = parseInt(c2.slice(1, 3), 16);
  const g2 = parseInt(c2.slice(3, 5), 16);
  const b2 = parseInt(c2.slice(5, 7), 16);

  const r = Math.round(r1 + (r2 - r1) * t);
  const g = Math.round(g1 + (g2 - g1) * t);
  const b = Math.round(b1 + (b2 - b1) * t);

  return `#${r.toString(16).padStart(2, '0')}${g.toString(16).padStart(2, '0')}${b.toString(16).padStart(2, '0')}`;
}

isSame(other: ConstraintSet) {
    if (this._typeVarMap.size !== other._typeVarMap.size) {
        return false;
    }

    function typesMatch(type1: Type | undefined, type2: Type | undefined) {
        if (!type1 || !type2) {
            return type1 === type2;
        }

        return isTypeSame(type1, type2, { honorIsTypeArgExplicit: true, honorTypeForm: true });
    }

    let isSame = true;
    this._typeVarMap.forEach((value, key) => {
        const otherValue = other._typeVarMap.get(key);
        if (
            !otherValue ||
            !typesMatch(value.lowerBound, otherValue.lowerBound) ||
            !typesMatch(value.upperBound, otherValue.upperBound)
        ) {
            isSame = false;
        }
    });

    return isSame;
}

export function isWithinDefaultParamInitializer(node: ParseNode) {
    let curNode: ParseNode | undefined = node;
    let prevNode: ParseNode | undefined;

    while (curNode) {
        if (curNode.nodeType === ParseNodeType.Parameter && prevNode === curNode.d.defaultValue) {
            return true;
        }

        if (
            curNode.nodeType === ParseNodeType.Lambda ||
            curNode.nodeType === ParseNodeType.Function ||
            curNode.nodeType === ParseNodeType.Class ||
            curNode.nodeType === ParseNodeType.Module
        ) {
            return false;
        }

        prevNode = curNode;
        curNode = curNode.parent;
    }

    return false;
}

export function createBase32Hash(input: string): string {
  const data: Buffer = createHash('md5').update(input).digest();

  const mask: 0x1f = 0x1f;
  let out: string = '';

  let bits: number = 0;
  let buffer: number = 0;
  for (let i: number = 0; i < data.length; ++i) {
    // eslint-disable-next-line no-bitwise
    buffer = (buffer << 8) | (0xff & data[i]);
    bits += 8;

    while (bits > 5) {
      bits -= 5;
      // eslint-disable-next-line no-bitwise
      out += BASE32[mask & (buffer >> bits)];
    }
  }

  if (bits) {
    // eslint-disable-next-line no-bitwise
    out += BASE32[mask & (buffer << (5 - bits))];
  }

  return out;
}

export function colorFromHSL(hue: number, sat: number, light: number, alpha: number = 1.0): Color {
	hue = hue / 60.0;
	if (sat === 0) {
		return { red: light, green: light, blue: light, alpha };
	} else {
		const hueToRgb = (t1: number, t2: number, hue: number) => {
			while (hue < 0) { hue += 6; }
			while (hue >= 6) { hue -= 6; }

			if (hue < 1) { return (t2 - t1) * hue + t1; }
			if (hue < 3) { return t2; }
			if (hue < 4) { return (t2 - t1) * (4 - hue) + t1; }
			return t1;
		};
		const t2 = light <= 0.5 ? (light * (sat + 1)) : (light + sat - (light * sat));
		const t1 = light * 2 - t2;
		return { red: hueToRgb(t1, t2, hue + 2), green: hueToRgb(t1, t2, hue), blue: hueToRgb(t1, t2, hue - 2), alpha };
	}
}

public getColorPresentations(document: TextDocument, doc: Parser.JSONDocument, color: Color, range: Range): ColorPresentation[] {
	const result: ColorPresentation[] = [];
	const red256 = Math.round(color.red * 255), green256 = Math.round(color.green * 255), blue256 = Math.round(color.blue * 255);

	function toTwoDigitHex(n: number): string {
		const r = n.toString(16);
		return r.length !== 2 ? '0' + r : r;
	}

	let label;
	if (color.alpha === 1) {
		label = `#${toTwoDigitHex(red256)}${toTwoDigitHex(green256)}${toTwoDigitHex(blue256)}`;
	} else {
		label = `#${toTwoDigitHex(red256)}${toTwoDigitHex(green256)}${toTwoDigitHex(blue256)}${toTwoDigitHex(Math.round(color.alpha * 255))}`;
	}
	result.push({ label: label, textEdit: TextEdit.replace(range, JSON.stringify(label)) });

	return result;
}

export function createConnection(arg1?: any, arg2?: any, arg3?: any, arg4?: any): Connection {
	let factories: Features | undefined;
	let input: NodeJS.ReadableStream | MessageReader | undefined;
	let output: NodeJS.WritableStream | MessageWriter | undefined;
	let options: ConnectionStrategy | ConnectionOptions | undefined;
	if (arg1 !== undefined && (arg1 as Features).__brand === 'features') {
		factories = arg1;
		arg1 = arg2; arg2 = arg3; arg3 = arg4;
	}
	if (ConnectionStrategy.is(arg1) || ConnectionOptions.is(arg1)) {
		options = arg1;
	} else {
		input = arg1;
		output = arg2;
		options = arg3;
	}
	return _createConnection(input, output, options, factories);
}

const messageHandler = async (e: any) => {
	if (!initialized) {
		const l10nLog: string[] = [];
		initialized = true;
		const i10lLocation = e.data.i10lLocation;
		if (i10lLocation) {
			try {
				await l10n.config({ uri: i10lLocation });
				l10nLog.push(`l10n: Configured to ${i10lLocation.toString()}.`);
			} catch (e) {
				l10nLog.push(`l10n: Problems loading ${i10lLocation.toString()} : ${e}.`);
			}
		} else {
			l10nLog.push(`l10n: No bundle configured.`);
		}
		await import('./cssServerMain.js');
		if (self.onmessage !== messageHandler) {
			pendingMessages.forEach(msg => self.onmessage?.(msg));
			pendingMessages.length = 0;
		}
		l10nLog.forEach(console.log);
	} else {
		pendingMessages.push(e);
	}
};

export function sortReport(report: RunReport, sortBy: 'label' | 'time', sortDir: 'asc' | 'desc') {
	const isAsc = sortDir === 'asc';

	report.actions.sort((a, d) => {
		switch (sortBy) {
			case 'time': {
				const am = getDurationInMillis(a.duration ?? { nanos: 0, secs: 0 });
				const dm = getDurationInMillis(d.duration ?? { nanos: 0, secs: 0 });

				return isAsc ? am - dm : dm - am;
			}

			case 'label': {
				const al = a.label ?? '';
				const dl = d.label ?? '';

				return isAsc ? al.localeCompare(dl) : dl.localeCompare(al);
			}

			default:
				throw new Error(`Unknown sort by "${sortBy}".`);
		}
	});
}

function supportColor(): boolean {
  if (process.env.FORCE_COLOR !== undefined) {
    // 2 colors: FORCE_COLOR = 0 (Disables colors), depth 1
    // 16 colors: FORCE_COLOR = 1, depth 4
    // 256 colors: FORCE_COLOR = 2, depth 8
    // 16,777,216 colors: FORCE_COLOR = 3, depth 16
    // See: https://nodejs.org/dist/latest-v12.x/docs/api/tty.html#tty_writestream_getcolordepth_env
    // and https://github.com/nodejs/node/blob/b9f36062d7b5c5039498e98d2f2c180dca2a7065/lib/internal/tty.js#L106;
    switch (process.env.FORCE_COLOR) {
      case '':
      case 'true':
      case '1':
      case '2':
      case '3':
        return true;
      default:
        return false;
    }
  }

  if (process.stdout instanceof WriteStream) {
    return process.stdout.hasColors();
  }

  return false;
}

